import React, { createContext, useState, useContext, useEffect } from 'react';
import axios from 'axios';

const CartContext = createContext();

export const CartProvider = ({ children }) => {
  const [cartItems, setCartItems] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  // Optionally load initial cart items from the database
  useEffect(() => {
    const fetchCart = async () => {
      try {
        const token = localStorage.getItem('token');
        if (!token) return;

        setLoading(true);
        const response = await axios.get("http://localhost:3000/api/v1/cart", {
          headers: { 'Authorization': `Bearer ${token}` }
        });
        
        // Filter out items with missing products
        const validItems = response.data.filter(item => item.product !== null);
        setCartItems(validItems);
        
      } catch (err) {
        console.error("Error fetching cart:", err);
        setError(err.message);
      } finally {
        setLoading(false);
      }
    };
    fetchCart();
  }, [localStorage.getItem('token')]); // Re-fetch when token changes

  const addToCart = async (product) => {
    try {
      const existingItem = cartItems.find((item) => item.product._id === product._id);

      if (existingItem) {
        // If the product is already in the cart, update the quantity
        existingItem.quantity += product.quantity;
        await axios.put(`http://localhost:3000/api/v1/cart/${existingItem._id}`, {
          quantity: existingItem.quantity
        });
      } else {
        // If the product is not in the cart, add it
        const newItem = { product, quantity: product.quantity };
        await axios.post(`http://localhost:3000/api/v1/cart`, newItem);
        setCartItems([...cartItems, newItem]);
      }
    } catch (err) {
      console.error("Error adding to cart:", err);
      setError(err.response?.data?.message || err.message);
    }
  };

  const removeFromCart = async (productId) => {
    try {
      const token = localStorage.getItem('token');
      if (!token) {
        throw new Error('Please login to remove items from cart');
      }

      await axios.delete(`http://localhost:3000/api/v1/cart/${productId}`, {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });
      setCartItems(cartItems.filter(item => item.product._id !== productId));
    } catch (err) {
      console.error("Error removing product from cart:", err);
      setError(err.response?.data?.message || err.message);
    }
  };

  const updateQuantity = async (productId, quantity) => {
    try {
      const token = localStorage.getItem('token');
      if (!token) {
        throw new Error('Please login to update cart');
      }

      const response = await axios.put(
        `http://localhost:3000/api/v1/cart/${productId}`,
        { quantity },
        {
          headers: {
            'Authorization': `Bearer ${token}`
          }
        }
      );

      if (response.data.success) {
        setCartItems(response.data.items);
      }
    } catch (err) {
      console.error("Error updating quantity:", err);
      setError(err.response?.data?.message || err.message);
    }
  };

  const clearCart = async () => {
    try {
      const token = localStorage.getItem('token');
      if (!token) {
        throw new Error('Please login to clear cart');
      }

      await axios.delete("http://localhost:3000/api/v1/cart", {
        headers: {
          'Authorization': `Bearer ${token}`
        }
      });
      setCartItems([]);
    } catch (err) {
      console.error("Error clearing cart", err);
      setError(err.response?.data?.message || err.message);
    }
  };

  const value = { cartItems, loading, error, addToCart, removeFromCart, updateQuantity, clearCart };

  return <CartContext.Provider value={value}>{children}</CartContext.Provider>;
};

export const useCart = () => useContext(CartContext);
